-- ============================================================================
  -- Phase 1 — Competency Taxonomy Expansion: 299 canonical competencies across
  -- 5 super-domains + 29 families. Builds on the seed in
  -- 20260523_competency_ontology_seed.sql (which seeded 13 illustrative comps).
  -- Idempotent: families ON CONFLICT DO NOTHING, competencies INSERT ... ON
  -- CONFLICT (id) DO UPDATE so re-applying refreshes metadata cleanly.
  -- ============================================================================

  -- ---- Pre-migration: rename legacy id alias and keep its FK refs intact -----
-- The original seed used `comp_stakeholder_mgmt` for "Stakeholder Management".
-- Many downstream tables (bench_*, onto_role_weights, etc.) FK-reference it,
-- so we KEEP the legacy id and just record the modern slug as an alias.
-- The bulk INSERT below excludes `comp_stakeholder_management` so the
-- legacy row remains the canonical entry.
  SELECT 'comp_stakeholder_mgmt', 'comp_stakeholder_management', 'comp_stakeholder_management', 'taxonomy_expansion_2026_09'
  WHERE EXISTS (SELECT 1 FROM onto_competencies WHERE id = 'comp_stakeholder_mgmt')
ON CONFLICT (competency_id, alias_normalized) DO NOTHING;

-- ---- Families (add the new ones; existing 10 from phase1 seed kept) -------
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  display_order = EXCLUDED.display_order;

